INSERT INTO room_members ( room_id, user_id, role, custom_room_name, custom_room_thumbnail, custom_room_back_ground, member_status, invited_at ) SELECT #{roomId}, u.user_id, 'MEMBER', cr.room_name, cr.room_thumbnail, NULL, 'ACTIVE', NOW() FROM users u JOIN chat_rooms cr ON cr.room_id = #{roomId} WHERE u.public_id IN
#{publicId}
AND u.status = 'ACTIVE' ON DUPLICATE KEY UPDATE role = IF(room_members.role = 'NONE', 'MEMBER', room_members.role), member_status = 'ACTIVE', left_at = NULL, kicked_at = NULL, invited_at = NOW(), rejoined_at = NOW()

mapper.update:
UPDATE room_members rm
JOIN users u
  ON u.user_id = rm.user_id
SET rm.role = #{targetRole}
WHERE rm.room_id = #{roomId}
  AND u.public_id = #{targetPublicId}
  AND rm.user_id != #{requesterUserId}
  AND rm.member_status = 'ACTIVE'
  AND rm.role != 'HOST'
